/**
 * SPEC-035: limpieza de UI de la captura — durante la grabación de una
 * CAPTURA ya no se pinta el área de transcripción en tiempo real, pero la
 * transcripción sigue corriendo por debajo: el badge de estado, el NoKeyAlert
 * y el asistente en vivo permanecen intactos. El detalle de entrevista
 * clásico conserva su área en vivo (SPEC-015 · AC-09, co-cobertura anotada en
 * el map — no se duplica aquí).
 * Generated by QA Dev agent.
 *
 * Arnés heredado de CaptureDetailPage.recordingControls.test.tsx (SPEC-034):
 * la ruta del detalle de captura montada BAJO <Layout/> (el arranque vive en
 * la cabecera vía capture-start-button y atraviesa el consentimiento de
 * SPEC-019 con localStorage limpio). Fronteras de mocking idénticas a
 * RecordingSection.test.tsx (SPEC-015): servicios del spike
 * (permissionsService/captureService/wavRecorderService) + bridge window.api.
 * Los eventos de transcripción y del asistente se inyectan con
 * emitTranscriptionStatus/emitTranscriptionResult/emitAssistantUpdate.
 */
import { act, render, screen, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { Layout } from '@/components/layout/Layout'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { CaptureDetailPage } from '@/pages/CaptureDetailPage'
import {
  acquireMicrophoneStream,
  acquireSystemAudioStream,
  listAudioInputDevices
} from '@/services/captureService'
import { getPermissionsStatus } from '@/services/permissionsService'
import type { Discovery, Interview } from '@/types/domain'
import { createFakeAudioStream } from '../../helpers/fakeMediaStream'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

vi.mock('@/services/permissionsService', () => ({
  getPermissionsStatus: vi.fn(),
  requestMicrophoneAccess: vi.fn(),
  openPrivacySettings: vi.fn()
}))

vi.mock('@/services/captureService', () => ({
  DEFAULT_DEVICE_ID: '__default__',
  acquireMicrophoneStream: vi.fn(),
  acquireSystemAudioStream: vi.fn(),
  listAudioInputDevices: vi.fn(),
  stopStream: vi.fn()
}))

const recorderMock = vi.hoisted(() => ({
  start: vi.fn(),
  stop: vi.fn(),
  getLevels: vi.fn(),
  durationSeconds: 0
}))

vi.mock('@/services/wavRecorderService', () => ({
  CAPTURE_SAMPLE_RATE: 16000,
  WavRecorderService: class {
    start = recorderMock.start
    stop = recorderMock.stop
    getLevels = recorderMock.getLevels
    get durationSeconds(): number {
      return recorderMock.durationSeconds
    }
    get samplesWritten(): number {
      return recorderMock.durationSeconds * 16000
    }
  }
}))

let mockApi: MockApiHandle

const DISCOVERY: Discovery = {
  id: 'd-1',
  name: 'Vertical Sanidad',
  createdAt: '2026-07-01T09:00:00.000Z',
  updatedAt: '2026-07-01T09:00:00.000Z'
}

function capture(overrides: Partial<Interview> = {}): Interview {
  return {
    id: 'i-1',
    discoveryId: 'd-1',
    companyId: null,
    contactId: null,
    templateId: null,
    title: 'Captura sin empresa',
    status: 'draft',
    scriptMarkdown: null,
    objectives: [],
    wavPath: null,
    transcriptPath: null,
    createdAt: '2026-07-10T10:00:00.000Z',
    updatedAt: '2026-07-10T10:00:00.000Z',
    ...overrides
  }
}

const LIVE_LINE_TEXT = 'Ya validamos el problema del registro manual'

const ASSISTANT_INITIAL_TEXT =
  'El asistente te sugerirá la siguiente pregunta en cuanto haya conversación.'

function setupGrantedCapture(): void {
  vi.mocked(getPermissionsStatus).mockResolvedValue({
    microphone: 'granted',
    systemAudio: 'granted'
  })
  vi.mocked(acquireMicrophoneStream).mockResolvedValue(createFakeAudioStream().stream)
  vi.mocked(acquireSystemAudioStream).mockResolvedValue(createFakeAudioStream().stream)
}

function renderCaptureDetail(): RenderResult {
  return render(
    <TooltipProvider>
      <MemoryRouter initialEntries={['/captures/i-1']}>
        <Routes>
          <Route path="/" element={<Layout />}>
            <Route path="captures/:id" element={<CaptureDetailPage />} />
          </Route>
        </Routes>
      </MemoryRouter>
      <Toaster />
    </TooltipProvider>
  )
}

/** La sección «Grabación» (el <section> que envuelve su heading). */
async function grabacionSection(): Promise<HTMLElement> {
  const heading = await screen.findByRole('heading', { name: 'Grabación' })
  const section = heading.closest('section')
  if (section === null) {
    throw new Error('El heading «Grabación» debe vivir dentro de un <section>')
  }
  return section
}

/**
 * Arranca la grabación desde el botón de la CABECERA (capture-start-button)
 * atravesando el aviso de consentimiento (SPEC-019) sin persistir preferencia.
 */
async function startFromHeader(user: ReturnType<typeof userEvent.setup>): Promise<void> {
  await user.click(await screen.findByTestId('capture-start-button'))
  const consent = await screen.findByRole('alertdialog')
  expect(within(consent).getByRole('heading', { name: 'Aviso de grabación' })).toBeInTheDocument()
  await user.click(within(consent).getByRole('button', { name: 'Entendido, iniciar grabación' }))
  await screen.findByRole('button', { name: 'Detener' })
}

/** Inyecta una línea final de transcripción (alimenta badge y asistente). */
function emitLiveLine(): void {
  act(() => {
    mockApi.emitTranscriptionStatus({ status: 'active' })
    mockApi.emitTranscriptionResult({
      channel: 'mic',
      text: LIVE_LINE_TEXT,
      startMs: 1000,
      endMs: 2600,
      receivedAtMs: 2700,
      isFinal: true,
      speaker: 0,
      offsetSeconds: 1
    })
  })
}

beforeEach(() => {
  vi.clearAllMocks()
  // Aislamiento: consentimiento SPEC-019 sin preferencia persistida
  window.localStorage.clear()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.getInterview).mockResolvedValue({ ok: true, data: capture() })
  vi.mocked(mockApi.api.db.getDiscovery).mockResolvedValue({ ok: true, data: DISCOVERY })
  // Sin Alert de clave en ScriptSection para no colisionar con los role=alert
  vi.mocked(mockApi.api.llm.getStatus).mockResolvedValue({
    ok: true,
    data: { hasAnthropicKey: true }
  })
  vi.mocked(listAudioInputDevices).mockResolvedValue([])
  vi.mocked(getPermissionsStatus).mockResolvedValue({
    microphone: 'granted',
    systemAudio: 'granted'
  })
  recorderMock.start.mockResolvedValue(undefined)
  recorderMock.stop.mockResolvedValue(undefined)
  recorderMock.getLevels.mockReturnValue({ microphone: 42, system: 17 })
  vi.mocked(mockApi.api.recording.stop).mockResolvedValue({
    filePath: '/tmp/maurya-recordings/captura-i-1.wav',
    durationSeconds: 95,
    sizeBytes: 44 + 95 * 16000 * 4,
    sampleRate: 16000,
    channels: 2,
    transcriptPath: null,
    latency: null,
    interview: null
  })
})

describe('CaptureDetailPage (SPEC-035 capture UI cleanup)', () => {
  describe('recording without live transcript area', () => {
    // SPEC-035 · AC-05
    it('records a capture without the live transcript area, keeping chronometer, Detener, status badge, assistant panel and level meters', async () => {
      const user = userEvent.setup()
      setupGrantedCapture()
      renderCaptureDetail()
      await startFromHeader(user)

      emitLiveLine()

      // La transcripción sigue corriendo (badge de estado)…
      expect(await screen.findByText('Transcribiendo')).toBeInTheDocument()
      // …pero NO se pinta en vivo: ni la línea, ni su hablante, ni el área
      // (su empty state «Esperando audio…» tampoco existe)
      expect(screen.queryByText(LIVE_LINE_TEXT)).not.toBeInTheDocument()
      expect(screen.queryByText('Hablante 1')).not.toBeInTheDocument()
      expect(screen.queryByText('Esperando audio…')).not.toBeInTheDocument()
      // El resto de la sesión en vivo sigue presente en la sección
      const section = await grabacionSection()
      expect(within(section).getByText('00:00')).toBeInTheDocument()
      expect(within(section).getByRole('button', { name: 'Detener' })).toBeInTheDocument()
      expect(within(section).getAllByRole('progressbar')).toHaveLength(2)
      expect(within(section).getByLabelText('Nivel de Micrófono')).toBeInTheDocument()
      expect(within(section).getByLabelText('Nivel de Sistema')).toBeInTheDocument()
      // SPEC-041 (derogación posicional, precedente SPEC-030): el panel del
      // asistente ya no vive dentro de la sección «Grabación» — la página lo
      // pinta arriba, en el contenedor assistant-live-section, mientras se
      // graba. El aserto funcional (panel presente durante la grabación de la
      // captura) se conserva en la nueva ubicación.
      expect(within(section).queryByText(ASSISTANT_INITIAL_TEXT)).not.toBeInTheDocument()
      const liveSection = screen.getByTestId('assistant-live-section')
      expect(within(liveSection).getByText(ASSISTANT_INITIAL_TEXT)).toBeInTheDocument()
    })

    // SPEC-035 · AC-06
    it('keeps showing the NoKeyAlert while a capture records without a Deepgram key', async () => {
      const user = userEvent.setup()
      setupGrantedCapture()
      renderCaptureDetail()
      await startFromHeader(user)

      act(() => {
        mockApi.emitTranscriptionStatus({ status: 'no-key' })
      })

      expect(await screen.findByText('Falta la key de Deepgram')).toBeInTheDocument()
      expect(screen.getByText('Sin key')).toBeInTheDocument()
      // La grabación sigue operativa y el área en vivo sigue sin pintarse
      expect(screen.getByRole('button', { name: 'Detener' })).toBeInTheDocument()
      expect(screen.queryByText('Esperando audio…')).not.toBeInTheDocument()
    })

    // SPEC-035 · AC-09
    it('keeps the live assistant producing suggestions from the unpainted transcription during a capture recording', async () => {
      const user = userEvent.setup()
      setupGrantedCapture()
      renderCaptureDetail()
      await startFromHeader(user)

      emitLiveLine()
      // SPEC-036: el evento transporta la cola completa (sustituye a suggestion)
      act(() => {
        mockApi.emitAssistantUpdate({
          state: 'active',
          queue: {
            pending: [
              {
                id: 'q-1',
                action: 'dig_deeper',
                suggestedQuestion: '¿Cuándo fue la última vez que os pasó?',
                reason: 'La afirmación es genérica: pide un ejemplo concreto',
                alarms: ['generic']
              }
            ],
            pinned: []
          },
          objectivesMet: []
        })
      })

      // El asistente funciona exactamente igual: sugerencia completa visible
      expect(await screen.findByText('¿Cuándo fue la última vez que os pasó?')).toBeInTheDocument()
      expect(
        screen.getByText('La afirmación es genérica: pide un ejemplo concreto')
      ).toBeInTheDocument()
      expect(screen.getByText('Profundiza')).toBeInTheDocument()
      expect(screen.getByText('Genérico')).toBeInTheDocument()
      // …aunque la transcripción que lo alimenta no se pinte
      expect(screen.queryByText(LIVE_LINE_TEXT)).not.toBeInTheDocument()
    })
  })
})
